export const MODEL_VERSION='CMO-Migraña v1.0 — julio de 2026';export const DIMENSIONS={demograficas:{label:'Variables demográficas',max:3},clinicas:{label:'Variables clínicas',max:10},farmacoterapeuticas:{label:'Variables farmacoterapéuticas',max:21},sociosanitarias:{label:'Variables sociosanitarias',max:6}};
const src='PDF no disponible en repositorio; pendiente de verificación literal';const opt=(id,label,score,definition,extra={})=>({id,label,score,definition,...extra});
export const VARIABLES=[['situacion_reproductiva','demograficas','Situación reproductiva','Embarazo, lactancia o deseo gestacional inminente clasifican automáticamente como Prioridad 1.',[opt('no_aplica','No aplica / sin situación de prioridad automática',0,'No consta embarazo, lactancia ni deseo gestacional inminente.'),opt('embarazo','Embarazo',0,'Situación de embarazo.',{automaticPriorityReason:'Embarazo'}),opt('lactancia','Lactancia',0,'Situación de lactancia.',{automaticPriorityReason:'Lactancia'}),opt('deseo_gestacional','Deseo gestacional inminente',0,'Deseo gestacional inminente en el periodo definido por el documento.',{automaticPriorityReason:'Deseo gestacional inminente'})]],['edad','demograficas','Edad','Los menores de 18 años deben valorarse mediante modelo CMO pediátrico.',[opt('menor_18','Menor de 18 años',0,'Requiere valoración mediante modelo pediátrico.',{pediatricReferral:true}),opt('adulto','18 años o más',0,'Aplicable al modelo adulto.')]],['sexo','demograficas','Sexo','Variable demográfica del modelo.',[opt('sin_riesgo','Sin puntuación adicional',0,'Opción sin puntuación adicional.'),opt('riesgo','Condición con puntuación demográfica',1,'Condición definida en el documento clínico.')]],['peso_estado_nutricional','demograficas','Peso/estado nutricional','Estado ponderal o nutricional según documento.',[opt('normal','Sin alteración relevante',0,'Sin puntuación adicional.'),opt('alterado','Alteración de peso/estado nutricional',2,'Alteración definida en el documento clínico.')]],['tipo_frecuencia_migrana','clinicas','Tipo o frecuencia de migraña','Incluye límites de frecuencia y definición temporal de migraña crónica del documento.',[opt('baja','Frecuencia baja/episódica de menor complejidad',0,'Según límites del documento.'),opt('alta','Frecuencia alta o migraña crónica',3,'Migraña crónica definida temporalmente en el documento.')]],['impacto_discapacidad','clinicas','Impacto/discapacidad HIT-6 o MIDAS','Puntos de corte HIT-6 y MIDAS según documento.',[opt('bajo','Impacto bajo',0,'Por debajo de puntos de corte del documento.'),opt('alto','Impacto/discapacidad alto',2,'HIT-6 o MIDAS en rango de alto impacto según documento.')]],['comorbilidades_psiquiatricas','clinicas','Comorbilidades psiquiátricas','Comorbilidades psiquiátricas recogidas en el documento.',[opt('no','No',0,'No constan.'),opt('si','Sí',1,'Presencia de comorbilidad psiquiátrica.')]],['comorbilidades_no_psiquiatricas','clinicas','Comorbilidades no psiquiátricas','Comorbilidades no psiquiátricas recogidas en el documento.',[opt('no','No',0,'No constan.'),opt('si','Sí',1,'Presencia de comorbilidad no psiquiátrica.')]],['comorbilidades_cardiovasculares','clinicas','Comorbilidades cardiovasculares','Comorbilidades cardiovasculares recogidas en el documento.',[opt('no','No',0,'No constan.'),opt('si','Sí',1,'Presencia de comorbilidad cardiovascular.')]],['pluripatologia','clinicas','Pluripatología','Pluripatología según definición operativa del documento.',[opt('no','No',0,'No cumple definición.'),opt('si','Sí',2,'Cumple definición de pluripatología.')]],['paciente_naive','farmacoterapeuticas','Paciente naïve/tratado','Condición informativa cuando corresponda.',[opt('tratado','Paciente tratado',0,'Informativo.'),opt('naive','Paciente naïve',0,'Informativo.')]],['via_administracion','farmacoterapeuticas','Vía de administración','Complejidad por vía de administración.',[opt('simple','Vía de menor complejidad',0,'Según documento.'),opt('compleja','Vía de administración compleja',3,'Según documento.')]],['riesgo_interacciones','farmacoterapeuticas','Riesgo de interacciones','Riesgo de interacciones farmacológicas.',[opt('no','No',0,'Sin riesgo relevante.'),opt('si','Sí',3,'Riesgo relevante.')]],['fracasos_anti_cgrp','farmacoterapeuticas','Fracasos previos a tratamientos anti-CGRP','Fracasos previos a tratamientos anti-CGRP.',[opt('no','No',0,'Sin fracasos.'),opt('si','Sí',3,'Con fracasos previos.')]],['uso_excesivo_sintomatica','farmacoterapeuticas','Uso excesivo de medicación sintomática','Criterios de uso excesivo de medicación sintomática según documento.',[opt('no','No',0,'No cumple criterios.'),opt('si','Sí',3,'Cumple criterios del documento.')]],['cambios_tratamiento','farmacoterapeuticas','Cambios en el tratamiento','Cambios en el tratamiento.',[opt('no','No',0,'Sin cambios.'),opt('si','Sí',2,'Cambio relevante.')]],['efectos_adversos','farmacoterapeuticas','Efectos adversos','Definición y gradación de efectos adversos según documento.',[opt('no','No',0,'No constan.'),opt('si','Sí',3,'Efectos adversos según gradación del documento.')]],['falta_adherencia','farmacoterapeuticas','Falta de adherencia','Falta de adherencia.',[opt('no','No',0,'Sin falta de adherencia.'),opt('si','Sí',2,'Falta de adherencia.')]],['medicamentos_alto_riesgo','farmacoterapeuticas','Medicamentos de alto riesgo','Referencia al listado de medicamentos de alto riesgo de ISMP-España.',[opt('no','No',0,'No constan.'),opt('si','Sí',2,'Según listado de medicamentos de alto riesgo de ISMP-España.')]],['consumo_cafeina','sociosanitarias','Consumo de cafeína','Consumo de cafeína.',[opt('adecuado','Sin consumo problemático',0,'Según documento.'),opt('alto','Consumo elevado/problemático',1,'Según documento.')]],['habitos_sueno','sociosanitarias','Hábitos del sueño','Hábitos del sueño.',[opt('adecuados','Adecuados',0,'Sin puntuación adicional.'),opt('alterados','Alterados',2,'Alteración de hábitos del sueño.')]],['nivel_socioeconomico','sociosanitarias','Nivel socioeconómico','Condiciones socioeconómicas desfavorables según documento.',[opt('favorable','Sin condiciones desfavorables',0,'No constan.'),opt('desfavorable','Condiciones desfavorables',2,'Según definición del documento.')]],['formacion_paciente','sociosanitarias','Formación del paciente','Dificultades de asimilación de pautas según documento.',[opt('sin_dificultad','Sin dificultad de asimilación',0,'No constan dificultades.'),opt('dificultad','Dificultades de asimilación de pautas',1,'Según definición del documento.')]]].map(([id,dimension,label,definition,options])=>({id,dimension,label,required:true,sourcePage:src,definition,options}));
export const THRESHOLDS={p1Min:19,p2Min:15,p2Max:18,p3Max:14,totalMax:40};export function calculatedPriority(score){return score>=19?1:score>=15?2:3}export const PERIODICITY={model:{always:['Al inicio del tratamiento.','Cuando exista un cambio en el tratamiento.'],byPriority:{1:'Cada 6 meses.',2:'Cada 12 meses.',3:'Cada 12 meses.'}},followUp:{always:['Cuando exista un cambio en el tratamiento o en la situación clínica que lo justifique.'],byPriority:{1:'Cada 3 meses.',2:'Cada 6 meses.',3:'Cada 12 meses.'}}};
export const INTERVENTIONS={3:{'Seguimiento farmacoterapéutico':['Revisar el tratamiento preventivo y sintomático registrado y comprobar adecuación, efectividad, seguridad, interacciones, adherencia y persistencia.'],'Educación, formación y seguimiento del paciente':['Educar al paciente en objetivos del tratamiento, uso correcto de la medicación y registro de crisis, síntomas y consumo de medicación sintomática.'],'Coordinación con el equipo asistencial':['Documentar las intervenciones farmacéuticas en el registro local del caso y comunicar incidencias clínicas relevantes al equipo asistencial.']},2:{'Seguimiento farmacoterapéutico':['Revisar cambios de pauta, combinaciones terapéuticas, vías de administración de mayor complejidad y aparición de incidencias.'],'Educación, formación y seguimiento del paciente':['Reforzar educación individualizada y seguimiento de adherencia, tolerabilidad y expectativas terapéuticas.'],'Coordinación con el equipo asistencial':['Coordinar con Neurología y otros profesionales las necesidades de seguimiento derivadas de cambios terapéuticos o situación clínica.']},1:{'Seguimiento farmacoterapéutico':['Realizar seguimiento farmacoterapéutico intensivo en pacientes de mayor complejidad, con especial atención a seguridad, efectividad e interacciones.'],'Educación, formación y seguimiento del paciente':['Establecer educación y seguimiento estrecho del paciente y/o persona cuidadora ante alta complejidad o prioridad automática.'],'Coordinación con el equipo asistencial':['Consensuar con Neurología un plan de seguimiento farmacoterapéutico para los pacientes de mayor complejidad.']}};
export function scoreCase(answers={},override){const contributions=VARIABLES.map(v=>{const o=v.options.find(x=>x.id===answers[v.id]);return{dimension:v.dimension,variableId:v.id,variable:v.label,option:o?.label,score:o?.score,missing:v.required&&!o,automaticPriorityReason:o?.automaticPriorityReason,pediatricReferral:!!o?.pediatricReferral}});const missing=contributions.filter(c=>c.missing).map(c=>c.variableId);const subtotals=Object.fromEntries(Object.keys(DIMENSIONS).map(d=>[d,contributions.filter(c=>c.dimension===d&&!c.missing).reduce((s,c)=>s+(c.score||0),0)]));const total=Object.values(subtotals).reduce((a,b)=>a+b,0);const auto=contributions.map(c=>c.automaticPriorityReason).filter(Boolean);const numericPriority=calculatedPriority(total);const algorithmPriority=auto.length?1:numericPriority;const finalPriority=override?.to??algorithmPriority;return{total,subtotals,contributions,missing,pediatric:contributions.some(c=>c.pediatricReferral),status:contributions.some(c=>c.pediatricReferral)?'Requiere valoración mediante modelo pediátrico':missing.length?'Provisional por información incompleta':'Calculado',numericPriority,automaticPriority:auto.length?1:undefined,automaticPriorityReasons:auto,algorithmPriority,finalPriority,override,periodicity:{model:[...PERIODICITY.model.always,PERIODICITY.model.byPriority[finalPriority]],followUp:[...PERIODICITY.followUp.always,PERIODICITY.followUp.byPriority[finalPriority]]}}}
export function dimensionMaxima(){return Object.fromEntries(Object.keys(DIMENSIONS).map(d=>[d,VARIABLES.filter(v=>v.dimension===d).reduce((s,v)=>s+Math.max(...v.options.map(o=>o.score)),0)]))}export function totalMaximum(){return Object.values(dimensionMaxima()).reduce((a,b)=>a+b,0)}export function cumulativeInterventions(p){return (p===1?[3,2,1]:p===2?[3,2]:[3]).flatMap(level=>Object.entries(INTERVENTIONS[level]).flatMap(([category,items])=>items.map(text=>({priority:level,category,text}))))}export function normalizeText(s){return s.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase()}export function assertNoExcludedInterventions(){const r=new RegExp('\\b'+'p'+'rm'+'\\b');const bad=cumulativeInterventions(1).filter(i=>r.test(normalizeText(i.text))||normalizeText(i.text).includes('problema relacionado con la medicacion')||normalizeText(i.text).includes('problemas relacionados con la medicacion'));if(bad.length)throw Error('Concepto excluido detectado')}export function exportJson(p){return JSON.stringify(p,null,2)}export function importJson(t){return JSON.parse(t)}export function exportCsv(rows){const keys=[...new Set(rows.flatMap(r=>Object.keys(r)))];return [keys.join(','),...rows.map(r=>keys.map(k=>JSON.stringify(r[k]??'')).join(','))].join('\n')}export function printableReport(pseudonym,answers,override){const r=scoreCase(answers,override);return`Resultado CMO-Migraña\nPaciente: ${pseudonym}\nPrioridad final: ${r.finalPriority}\nPuntuación: ${r.total}/40\nExplicación: ${r.contributions.map(c=>`${c.variable}: ${c.option??'pendiente'} (${c.score??'sin dato'})`).join('; ')}\nPeriodicidad reevaluación: ${r.periodicity.model.join(' ')}\nPeriodicidad seguimiento: ${r.periodicity.followUp.join(' ')}\nIntervenciones: incluidas según prioridad acumulativa.`}
